module shift_register_8bit(
    input clk, reset,
    input [7:0] d,
    output reg [7:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) 
            q <= 8'b0;
        else 
            q <= {q[6:0], d[7]};
    end
endmodule
